// BillsHistory.jsx
import React, { useEffect, useState } from "react";

const API_BASE = "https://prasa-app-yde3.onrender.com/api";
const green = "#0f9d58";
const light = "#eaf8f0";

export default function BillsHistory({ employee }) {
  const [bills, setBills] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchBills();
  }, [employee]);

  const fetchBills = async () => {
    try {
      const empId = employee.empld;
      const res = await fetch(`${API_BASE}/bills?empId=${empId}`);
      const data = await res.json();
      const rows = Array.isArray(data) ? data : data.records || data.rows || [];
      setBills(rows);
    } catch (err) {
      console.error("Bills history error:", err);
      setBills([]);
    }
  };

  const filtered = bills.filter((b) => {
    const d = new Date(b.uploaded_at || b.uploadedAt || b.created_at);
    const f = fromDate ? new Date(fromDate) : null;
    const tt = toDate ? new Date(toDate) : null;
    if (f && d < f) return false;
    if (tt && d > tt) return false;
    return true;
  });

  const downloadReport = () => {
    alert("Downloading Bills Report (backend PDF route can be added later)");
  };

  return (
    <div style={{ background: light, minHeight: "100vh", padding: 20 }}>
      <div style={{ maxWidth: 900, margin: "0 auto", background: "#fff", borderRadius: 18, padding: 20, boxShadow: "0 4px 15px rgba(0,0,0,0.1)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button onClick={() => window.history.back()} style={{ background: light, border: "none", padding: "8px 12px", borderRadius: 10, cursor: "pointer" }}>←</button>
          <h2 style={{ margin: 0, color: green }}>Bills History</h2>
        </div>

        <p style={{ marginTop: 5, fontSize: 15, color: "#444" }}>
          Employee: <b>{employee?.name}</b> • {employee?.empld}
        </p>

        <div style={{ background: "#F1FAF4", padding: 18, borderRadius: 12, marginTop: 12 }}>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            <div style={{ flex: 1 }}>
              <label>From Date</label>
              <input type="date" value={fromDate} onChange={(e) => setFrom(e.target.value)} style={{ width: "100%", padding: 10, borderRadius: 8, border: "1px solid #ccc", marginTop: 4 }} />
            </div>

            <div style={{ flex: 1 }}>
              <label>To Date</label>
              <input type="date" value={toDate} onChange={(e) => setTo(e.target.value)} style={{ width: "100%", padding: 10, borderRadius: 8, border: "1px solid #ccc", marginTop: 4 }} />
            </div>

            <button onClick={() => { setFrom(""); setTo(""); fetchBills(); }} style={{ padding: "10px 18px", background: green, color: "white", border: "none", borderRadius: 8, height: "40px", marginTop: 22, cursor: "pointer" }}>
              Reset
            </button>
          </div>

          <button onClick={fetchBills} style={{ width: "100%", background: green, color: "white", border: "none", borderRadius: 10, padding: 12, marginTop: 12, fontSize: 16, cursor: "pointer" }}>
            Apply Filters
          </button>
        </div>

        <div style={{ background: "white", borderRadius: 12, marginTop: 15, padding: 15, border: "1px solid #E0E0E0" }}>
          <table style={{ width: "100%", textAlign: "left" }}>
            <thead>
              <tr style={{ background: "#F1FAF4" }}>
                <th style={{ padding: 10 }}>Date</th>
                <th style={{ padding: 10 }}>File Name</th>
                <th style={{ padding: 10 }}>Preview</th>
              </tr>
            </thead>

            <tbody>
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan="3" style={{ textAlign: "center", padding: 20 }}>No bills found</td>
                </tr>
              ) : (
                filtered.map((b) => (
                  <tr key={b.id || b.bill_id}>
                    <td style={{ padding: 10 }}>{(b.uploaded_at || b.uploadedAt || b.created_at || "").substring(0, 10)}</td>
                    <td style={{ padding: 10 }}>{b.file_name || b.original_name || (b.file_path || "").split("/").pop()}</td>
                    <td style={{ padding: 10 }}>
                      <a href={b.file_path || b.file_path_full || b.file} target="_blank" rel="noreferrer" style={{ color: green, fontWeight: 600 }}>
                        View
                      </a>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div style={{ marginTop: 20 }}>
          <button onClick={downloadReport} style={{ background: green, color: "white", padding: "12px 20px", border: "none", borderRadius: 10, cursor: "pointer" }}>
            📄 Download Bills Report
          </button>
        </div>
      </div>
    </div>
  );
}
